glsl3.vert:
  precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
  in vec3 a_position;
  in vec4 a_color;
  out vec4 v_color;
  #if USE_TEXTURE
  in vec2 a_uv0;
  out vec2 v_uv0;
  #endif
  uniform PointData {
    vec4 xlist = vec4(0.0,0.0,0.0,0.0);
    vec4 ylist = vec4(0.0,0.0,0.0,0.0);
    vec4 xlistSymmetricPos = vec4(0.0,0.0,0.0,0.0);
    vec4 ylistSymmetricPos = vec4(0.0,0.0,0.0,0.0);
    vec2 disX = vec2(0.0,0.0);
    vec2 disY = vec2(0.0,0.0);
    vec2 disYSymmetricPos = vec2(0.0,0.0);
    vec2 disXSymmetricPos = vec2(0.0,0.0);
    vec2 worldPos = vec2(0.0,0.0);
    float sprWidth = 0.0;
    float sprHight = 0.0;
    float worldSprWidth = 0.0;
    float worldSprHeight = 0.0;
  };
  vec2 getSymmetricPos(vec2 sp,vec2 pos1, vec2 pos2)
{
    float disX = pos2.x - pos1.x;
    float disY = pos2.y - pos1.y;
    if (disX == 0.0)
    {
        float x = pos1.x - sp.x;
        return vec2(pos1.x + x,sp.y);
    }
    float k1 = disY/disX;
    float y = (sp.y*k1*k1  + sp.x*k1 + k1*sp.x - k1*pos1.x*2.0 + pos1.y*2.0 - sp.y)/(1.0+k1*k1);
    float x = (y - sp.y)/(-1.0/k1)+sp.x;
    return vec2(x,y);
}
  void main () {
    vec2 pos1 = vec2(0.0,0.0);
    vec2 pos2 = vec2(0.0,0.0);
    if (disXSymmetricPos[0] != 0.0 || disXSymmetricPos[1] != 0.0)
    {
        if (disXSymmetricPos[0] == 0.0)
        {
            pos1 = vec2(disXSymmetricPos[1] + worldPos.x,worldPos.y);
            pos2 = vec2(disXSymmetricPos[1] + worldPos.x,worldPos.y+worldSprHeight);
        }
        else
        {
            pos1 = vec2(disXSymmetricPos[0] + worldPos.x,worldPos.y);
            pos2 = vec2(disXSymmetricPos[0] + worldPos.x,worldPos.y+worldSprHeight);
        }
    }
    else if (disYSymmetricPos[0] != 0.0 || disYSymmetricPos[1] != 0.0)
    {
        if (disYSymmetricPos[0] == 0.0)
        {
            pos1 = vec2(worldPos.x,(worldSprHeight - disYSymmetricPos[1]) + worldPos.y);
            pos2 = vec2(worldPos.x + worldSprWidth, (worldSprHeight - disYSymmetricPos[1]) + worldPos.y);
        }
        else
        {
            pos1 = vec2(worldPos.x, (worldSprHeight - disYSymmetricPos[0]) + worldPos.y);
            pos2 = vec2(worldPos.x + worldSprWidth, (worldSprHeight - disYSymmetricPos[0]) + worldPos.y);
        }
    }
    else if(xlistSymmetricPos.x != 0.0 || xlistSymmetricPos.y != 0.0 || xlistSymmetricPos.z != 0.0){
        pos1 = vec2(xlistSymmetricPos.y+worldPos.x,worldSprHeight - ylistSymmetricPos.y + worldPos.y);
        pos2 = vec2(xlistSymmetricPos.z+worldPos.x,worldSprHeight - ylistSymmetricPos.z + worldPos.y);
    }
    vec2 sp = vec2(a_position.x, a_position.y);
    vec2 symmetricPos = getSymmetricPos(sp,pos1,pos2);
    vec4 tmp_pos = vec4(a_position.x, a_position.y,a_position.z, 1.0);
    tmp_pos.x = symmetricPos.x ;
    tmp_pos.y = symmetricPos.y ;
    vec4 pos = tmp_pos;
    #if CC_USE_MODEL
    pos = cc_matViewProj * cc_matWorld * pos;
    #else
    pos = cc_matViewProj * pos;
    #endif
    #if USE_TEXTURE
    v_uv0 = a_uv0;
    #endif
    v_color = a_color;
    gl_Position = pos ;
  }

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
      if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
      if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 v_color;
#if USE_TEXTURE
in vec2 v_uv0;
uniform sampler2D texture;
#endif
uniform PointData {
  vec4 xlist = vec4(0.0,0.0,0.0,0.0);
  vec4 ylist = vec4(0.0,0.0,0.0,0.0);
  vec4 xlistSymmetricPos;
  vec4 ylistSymmetricPos;
  vec2 disX = vec2(0.0,0.0);
  vec2 disY = vec2(0.0,0.0);
  vec2 disYSymmetricPos;
  vec2 disXSymmetricPos;
  vec2 worldPos;
  float sprWidth = 0.0;
  float sprHight = 0.0;
  float worldSprWidth;
  float worldSprHeight;
};
bool isHide(float px , float py)
{
  float dx = px * sprWidth;
  float dy = py * sprHight;
  if (disX[0] != 0.0 || disX[1] != 0.0)
  {
    return dx >= disX[0] && dx <= disX[1];
  }
  else if (disY[0] != 0.0 || disY[1] != 0.0)
  {
    return dy >= disY[0] && dy <= disY[1];
  }
  vec2 p1 = vec2(xlist[0], ylist[0]);
  vec2 p2 = vec2(xlist[1], ylist[1]);
  vec2 p3 = vec2(xlist[2], ylist[2]);
  if (p1 == vec2(0.0) && p2 == vec2(0.0) && p3 == vec2(0.0))
  {
    return false;
  }
  vec2 v  = p3 - p2;
  float sideRef = v.x * (p1.y - p2.y) - v.y * (p1.x - p2.x);
  float sidePt  = v.x * (dy    - p2.y) - v.y * (dx    - p2.x);
  float eps = 1e-4;
  if (abs(sideRef) < eps) {
    return false;
  }
  return (sideRef > 0.0 && sidePt > eps) || (sideRef < 0.0 && sidePt < -eps);
}
void main () {
  vec4 o = vec4(1, 1, 1, 1);
  #if USE_TEXTURE
  vec4 texture_tmp = texture(texture, v_uv0);
  #if CC_USE_ALPHA_ATLAS_texture
      texture_tmp.a *= texture(texture, v_uv0 + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    o.rgb *= (texture_tmp.rgb * texture_tmp.rgb);
    o.a *= texture_tmp.a;
  #else
    o *= texture_tmp;
  #endif
  #endif
  o *= v_color;
  ALPHA_TEST(o);
  bool hide = isHide(v_uv0.x,v_uv0.y);
  if (!hide)
  {
    o.a = 0.0;
  }
  gl_FragColor = o;
}

